import sys

class Solution:
    def solve(self, nums: list[int], X: int) -> list[int]:
        # Build BST nodes as dicts
        class Node:
            __slots__ = ('val', 'left', 'right')
            def __init__(self, v):
                self.val = v
                self.left = None
                self.right = None
        root = None
        def insert(node: Node, v: int) -> Node:
            if node is None:
                return Node(v)
            if v < node.val:
                node.left = insert(node.left, v)
            else:
                node.right = insert(node.right, v)
            return node
        for v in nums:
            root = insert(root, v)
        # Find floor and ceil
        floor = -1
        ceil = -1
        cur = root
        while cur:
            if cur.val == X:
                floor = ceil = cur.val
                break
            if cur.val < X:
                floor = cur.val
                cur = cur.right
            else:
                ceil = cur.val
                cur = cur.left
        return [floor, ceil]

if __name__ == '__main__':
    data = sys.stdin.read().split()
    if not data:
        sys.exit(0)
    it = iter(data)
    n = int(next(it))
    nums = [int(next(it)) for _ in range(n)]
    X = int(next(it))
    sol = Solution()
    ans = sol.solve(nums, X)
    print(' '.join(map(str, ans)))

