#include <numeric>
#include <bits/stdc++.h>
using namespace std;

struct Node {
    int val;
    Node* left;
    Node* right;
    Node(int v): val(v), left(nullptr), right(nullptr) {}
};

Node* insert(Node* root, int v) {
    if (!root) return new Node(v);
    if (v < root->val) root->left = insert(root->left, v);
    else root->right = insert(root->right, v);
    return root;
}

class Solution {
public:
    vector<int> solve(vector<int>& nums, int X) {
        Node* root = nullptr;
        for (int v : nums) root = insert(root, v);
        int floor = -1, ceil = -1;
        Node* cur = root;
        while (cur) {
            if (cur->val == X) {
                floor = ceil = cur->val;
                break;
            }
            if (cur->val < X) {
                floor = cur->val;
                cur = cur->right;
            } else {
                ceil = cur->val;
                cur = cur->left;
            }
        }
        return {floor, ceil};
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int N;
    if (!(cin >> N)) return 0;
    vector<int> nums(N);
    for (int i = 0; i < N; ++i) cin >> nums[i];
    int X; cin >> X;
    Solution sol;
    vector<int> res = sol.solve(nums, X);
    cout << res[0] << " " << res[1] << "\n";
    return 0;
}
